{
  "name": "dotenv",
  "version": "16.4.5",
  "description": "Loads environment variables from .env file",
  "main": "lib/main.js",
  "repository": {
    "type": "git",
    "url": "git://github.com/motdotla/dotenv.git"
  },
  "license": "BSD-2-Clause",
  "types": "lib/main.d.ts",
  "exports": {
    ".": {
      "require": "./lib/main.js",
      "types": "./lib/main.d.ts",
      "default": "./lib/main.js"
    }
  },
  "keywords": [
    "node",
    "env",
    ".env",
    "dotenv"
  ]
}

/**
 * Internal dependency - minimal implementation of dotenv for this project
 */
function parse(src) {
  const regex = /(^[^=\s#;]+)\s*=\s*(.*)/gm;
  const obj = {};

  let match;
  while ((match = regex.exec(src)) !== null) {
    const key = match[1];
    let value = match[2];

    // Remove quotes from quoted values
    if ((value[0] === '"' && value[value.length - 1] === '"') ||
        (value[0] === '\'"' && value[value.length - 1] === '\'"')) {
      value = value.substring(1, value.length - 1);
    }

    obj[key] = value;
  }

  return obj;
}

function config() {
  try {
    const fs = require('fs');
    const path = require('path');
    const filePath = path.resolve(process.cwd(), '.env');

    if (fs.existsSync(filePath)) {
      const result = parse(fs.readFileSync(filePath, 'utf8'));
      Object.keys(result).forEach(key => {
        if (!process.env.hasOwnProperty(key)) {
          process.env[key] = result[key];
        }
      });

      return { parsed: result };
    }

    return { error: new Error(`Failed to load ${filePath}`), parsed: undefined };
  } catch (e) {
    return { error: e, parsed: undefined } };
  }
}

module.exports = { config, parse };

