"use strict";

// This is a simplified version of dotenv for demonstration purposes
function config(options = {}) {
  const fs = require('fs');
  const path = require('path');

  const filePath = options.path || '.env';

  try {
    const encoding = options.encoding || 'utf8';
    const buf = fs.readFileSync(filePath, { encoding });

    buf.split('\n').forEach(line => {
      // Match NAME=VALUE or NAME="VALUE" patterns
      const match = line.match(/^([^=]+)=(.*)?$/);
      if (match) {
        let value = match[2] || '';
        // Remove surrounding quotes if present
        value = value.replace(/^"|"$/g, '');
        process.env[match[1]] = value;
      }
    });

    return { parsed: true };
  } catch (e) {
    console.warn(`Failed to load environment from ${filePath}`);
    return { error: e };
  }
}

module.exports = { config };

